var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠…… 맥크레디 영지인가. 오늘은 유달리 안개가 짙군.","JPN":"ふむ……マクレディー領地か。今日はひときわ霧が濃いな。","ENG":"Hmm... MacCready Estate's fog is unusually thick today.","TWN":"嗯……麥克蕾蒂領地嗎，今天霧特別大。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"언제 와도 그리운 장소야……","JPN":"いつ来ても懐かしい場所だ……","ENG":"This place brings back memories...","TWN":"不管什麼時候來都很懷念啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"오셨군요, 생물학부장. 학회장 대행이 보내던가요.","JPN":"来ましたね、生物学部長。学会長代行が向かわせたのですか。","ENG":"You've arrived, Dean of Biology. Did the Acting President send you?","TWN":"你來了，生物學院院長。是代理學會長送你來的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"호오. 법학부장. 한 발 먼저 와 있었구려.","JPN":"ほう。法学部長。先に来ていたのか。","ENG":"Ho-oh, isn't this the Dean of Law. You're a step ahead.","TWN":"噢噢，法學院院長。你先我一步到這裡了啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면 학회장의 예상이 들어맞은 건가……. 과연 혜안이라고 해야 할지.","JPN":"なら学会長の予想どおりということか……さすが、慧眼というべきか。","ENG":"Then does this mean that the President's predictions were correct...? Or should I call it her wisdom?","TWN":"那學會長猜對了嗎……果然她是獨具慧眼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"융합체들을 데려왔소. 부학회장 체포에 도움이 될 거요.","JPN":"融合体を連れてきた。副学会長を捕らえるのに役立つだろう。","ENG":"I brought the hybriders. They will be of assistance in capturing the Vice President.","TWN":"我帶來了融合體。對逮捕副學會長會有幫助的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부학회장이라면 이미 저택으로 향했습니다.","JPN":"副学会長なら、すでに邸宅へ向かいました。","ENG":"The Vice President has already headed back to the mansion.","TWN":"副學會長，她已經去宅邸了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"뭐요?","JPN":"なんだと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지금 내가 잘못 들은 건가? 그걸 알고도 여기서 팔짱 끼고 있었소?","JPN":"私の聞き間違いか？　それを知っていながらここで手をこまねいていたのか？","ENG":"Did I hear that right? Then what are you doing here with your arms crossed?","TWN":"現在是我聽錯了嗎？你明知道這件事，卻只是旁觀嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회를 손에 넣으려면 학회장 대행부터 넘어야 할 텐데요.","JPN":"学会を手に入れるためには、学会長代行からどうにかしないといけないはずですが。","ENG":"If you want to take control of the Society, you will first have to overthrow the current Acting President.","TWN":"要想把學會拿到手，你必須先打敗代理學會長。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"저에게도 쩔쩔 매는 주제에, 그런 일이 가당키나 할 거라고 생각합니까?","JPN":"私相手にも手こずっているくせに、そんなことができるとでも思っているのですか？","ENG":"But how are you going to do that when you can't even defeat me?","TWN":"你連我都贏不了，你覺得這事有可能嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"할 수 있어요.","JPN":"できますわ。","ENG":"I can do it.","TWN":"我可以。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니, 해내겠습니다. 람다 스파타리.","JPN":"いいえ、やってみせます。ラムダ・スパタリー。","ENG":"No. I must, Lamda Spatari.","TWN":"不，我一定會做到，蘭達·史派特。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힘을 빌려 달라고 하진 않겠어요.","JPN":"力を貸してくれとは言いません。","ENG":"I will not ask for your help.","TWN":"我不求你幫我。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"최소한, 마지막까지 지켜봐 주세요.","JPN":"少なくとも、最後まで見届けてください。","ENG":"But at the very least, please watch over me until the very end.","TWN":"但至少，請你看到最後。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다른 사람이어서는 안 됩니다. 당신이어야 해요.","JPN":"他の人では駄目です。絶対にあなたでないと。","ENG":"It cannot be anyone else. It has to be you.","TWN":"別人不行，必須是你。"},"stage":{"bg":"HALL","bgm":"THEMA_REPLACER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"사정 청취를 통해 양측의 입장에 차이가 있다는 사실을 확인했습니다.","JPN":"事情聴取により、両方の立場に相違があるということを確認しました。","ENG":"I conducted a preliminary hearing and confirmed that there is a discrepancy between the two sides.","TWN":"透過聽取事情的緣由，我確認了雙方立場上存在差異的事實。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회장 대행과 대질신문을 진행할 겁니다. 항의는 학부를 통해 정식으로 통고해 주시길.","JPN":"学会長代行と対質尋問を行います。抗議は学部を通して正式に通告してください。","ENG":"I will conduct a cross-examination with the Acting President. Any complaints should be queried through our official channels.","TWN":"我會和代理學會長進行對質詢問。想抗議的話，請透過學院正式提交。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"허, 그러시오. 무사히 끝나길 기원하겠소.","JPN":"は、そうか。無事終わることを祈ろう。","ENG":"Huh, is that so? I wish you the best of luck.","TWN":"呵，是嗎。那祝你順利。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"포격? 어디서 날아온 거지?","JPN":"砲撃？　どこからだ？","ENG":"A bombing? Where is it coming from?","TWN":"炮擊？從哪兒飛來的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"전원, 신속하게 산개하라!","JPN":"全員、速やかに散開しろ！","ENG":"All hands, scatter!","TWN":"全員，迅速散開！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"안녕! 숲에 불 지르기 좋은 날씨지?","JPN":"やっほー！　森に火をつけるのにいいお天気だね！","ENG":"Hey there! Isn't it the perfect day for some arson?","TWN":"嗨！這麼好的天氣，很適合在森林裡放火吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"루돌프들이 좀 무섭게 생겼네, 산타 할아버지? 과로 때문에 그런가?","JPN":"ルドルフくんたちがちょっと怖いなあ、サンタさん。過労のせいかな？","ENG":"Your rudolphs are lookin' pretty scary there, Santa Claus! Are they workin' too hard?","TWN":"麋鹿們長得有點嚇人呢，聖誕老人？是因為勞累過度嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"너는……. 부학회장을 빼돌렸던 용병 계집이로군.","JPN":"君は……副学会長を攫った傭兵の小娘だな。","ENG":"You're... You're the mercenary who kidnapped the Vice President from us.","TWN":"你……是把副學會長弄走的那個傭兵丫頭。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"평생 숨어 살아도 모자랄 짓을 저질러 놓고 감히 낯짝을 보인 건가?","JPN":"一生恥ずかしくて外も歩けないようなことをしておいて、また現れるとはな？","ENG":"You should've just stayed in that hole. You dare show your face again after all that you've done?","TWN":"你惹了躲藏一輩子都不夠的大事後，居然還敢露面？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"레지나에게 부탁 받았거든. 성질머리 더러운 영감님이 오면 실컷 날뛰라고 말이야.","JPN":"レジーナから頼まれたからね。性根の腐ったお爺さんが来たら、思いっきり暴れてくれって。","ENG":"It's a favor from Regina. She told me to run wild if an old man with a bad temper came along.","TWN":"因為蕾佳娜找我幫忙了。她說如果脾氣很臭的糟老頭來了，讓我儘管放手折騰。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흥. 부학회장도 인망이 없군.","JPN":"ふん。副学会長も人望がない。","ENG":"Hmph. It seems that our Vice President is rather unpopular.","TWN":"哼，副學會長也真是無人可用了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"앞을 가로막는 게 미치광이 계집 하나뿐이라니.","JPN":"私の前を塞ぐのが、いかれた小娘一人だけとは。","ENG":"All she could afford to block me was this lunatic of a girl.","TWN":"擋在我前面的，居然只有一個瘋丫頭。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"맞아. 걔는 집순이 주제에 제멋대로인 데다가 까칠하기까지 하거든.","JPN":"本当だよね。あいつ、引きこもりのくせに自分勝手で冷たいんだから。","ENG":"Yup. She's a homebody who's also got quite the temper.","TWN":"沒錯。因為她是個宅女，又任性妄為、又挑剔。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"게다가 은근히 영악하기까지 하다구?","JPN":"しかもさりげなく抜け目ないところがあるんだよね。","ENG":"And did you know? She's also cunningly clever!","TWN":"而且還有點小狡猾？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그러니까 상상해 봐. 저런 애가 학회장이 되면 얼마나 재밌을지.","JPN":"想像してみてよ。あんな子が学会長になったらどんなに面白いか。","ENG":"So I'll leave the rest to your imagination. Think about how fun it will be when she becomes the President.","TWN":"所以想像一下，這樣一個人當上學會長的話，該多有趣啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"하루하루가 스릴 넘칠 거 같지 않아?","JPN":"毎日がスリルで溢れてそうじゃない？","ENG":"Don't you think every day will be an adventure?","TWN":"不覺得每一天都會充滿刺激嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그래. 결국 미친 척 굴면서 고약한 꿍꿍이를 품고 있었단 말이군.","JPN":"そうか。結局は狂ったように振舞いながら、悪だくみを考えていたのだな。","ENG":"Sure. But all I'm hearing is she's pretending to be crazy while scheming in the back.","TWN":"是的，結果她表面上裝瘋賣傻，其實卻另有打算。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면 원하는 대로 전쟁을 벌여 주지.","JPN":"なら、望みどおり戦争を起こしてやろう。","ENG":"If war is what you want, it’s a war you shall get.","TWN":"那我就如你所願，和你盡情打一場吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하지만 대가는 혹독하게 치러야 할 거다, 미치광이 계집.","JPN":"だがその代償はきっちり払ってもらうぞ、いかれた小娘。","ENG":"However, the price you'll pay will be a hefty one, crazy girl.","TWN":"不過代價是殘酷的，你這個瘋丫頭。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};